mapper.select:
SELECT * FROM `order` WHERE user_id = #{userId} AND deleted = 0
AND store_id = #{storeId}
AND status = #{status}
ORDER BY id DESC LIMIT #{offset}, #{size}

SELECT COUNT(*) FROM `order` WHERE user_id = #{userId} AND deleted = 0
AND store_id = #{storeId}
AND status = #{status}

SELECT * FROM `order`
WHERE status = 'CREATED' AND create_time < #{deadline} AND deleted = 0
ORDER BY id LIMIT #{limit}

SELECT o.*, u.nickname, u.phone
FROM `order` o
LEFT JOIN `user` u ON u.id = o.user_id AND u.deleted = 0
WHERE o.deleted = 0
AND o.store_id = #{storeId}
AND o.order_no = #{orderNo}
AND o.status = #{status}
ORDER BY o.id DESC LIMIT #{offset}, #{size}

SELECT COUNT(*) FROM `order` o WHERE o.deleted = 0
AND o.store_id = #{storeId}
AND o.order_no = #{orderNo}
AND o.status = #{status}
